using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 writes "$type" instead of "Discriminator".
            // Existing 500K documents and raw SQL (c.Discriminator = 'Product')
            // require the old name.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id-to-JSON mapping changed.
            // EF Core 9 maps the CLR Id directly to JSON "id" as the raw value ("123").
            // EF Core 8 used a shadow property "__id" with format "Product|123".
            // Keep CLR Id on the JSON property "Id" (capital I) and use an explicit
            // CosmosId property for the JSON "id" to preserve the old format.
            b.Property(p => p.Id).ToJsonProperty("Id");
            b.Property(p => p.CosmosId).ToJsonProperty("id");

            // BREAKING CHANGE 3 — HasIndex now throws for Cosmos provider.
            // It was silently ignored in EF Core 8. Manage indexing through the
            // Cosmos DB indexing policy instead.
            // Removed: b.HasIndex(p => p.Sku);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = "";

    // Preserves the EF Core 8 id format ("Product|{key}") so that existing
    // documents remain readable and new documents stay consistent.
    private string? _cosmosId;
    public string CosmosId
    {
        get => _cosmosId ?? $"Product|{Id}";
        set => _cosmosId = value;
    }
}

