using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // BREAKING CHANGE 4 — Synchronous LINQ operators (ToList, First, Single, …)
    // now throw InvalidOperationException for the Cosmos provider in EF Core 9.
    // All queries must use their async counterparts.
    async Task FindProducts(ProductContext ctx)
    {
        // Raw Cosmos SQL — still works because we kept "Discriminator" as the
        // JSON property name (see ProductContext).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

